const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

app.use(helmet());
app.use(express.json({ limit: '10kb' }));

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

const client = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200',
  auth: {
    username: process.env.ES_USERNAME || 'elastic',
    password: process.env.ES_PASSWORD || 'changeme',
  },
});

// Allowed indices whitelist - only indices the admin dashboard should access
const ALLOWED_INDICES = (process.env.ALLOWED_INDICES || '').split(',').filter(Boolean);

// Blocked index patterns - system/security indices that should never be queried
const BLOCKED_INDEX_PATTERNS = [
  /^\.security/,
  /^\.kibana/,
  /^\.apm/,
  /^\.tasks/,
  /^\.management/,
  /^\.monitoring/,
  /^\.watches/,
  /^\.triggered_watches/,
  /^\.watcher-history/,
  /^\.ml-/,
  /^\.transform/,
  /^\.async-search/,
  /^\.slm-history/,
  /^\.ilm-history/,
  /^_all$/,
];

// Maximum result size to prevent excessive data extraction
const MAX_RESULT_SIZE = 100;
const MAX_FROM = 10000;

// Blocked query types that could be dangerous
const BLOCKED_QUERY_KEYS = [
  'script',
  'script_score',
  'script_fields',
  'scripted_metric',
  'runtime_mappings',
];

function validateIndexName(indexName) {
  if (!indexName || typeof indexName !== 'string') {
    return { valid: false, reason: 'Index name is required and must be a string' };
  }

  // Prevent path traversal and special characters
  if (/[\/\\*?\"<>|, ]/.test(indexName)) {
    return { valid: false, reason: 'Index name contains invalid characters' };
  }

  // Prevent wildcard patterns that could match system indices
  if (indexName.startsWith('.') || indexName.startsWith('_')) {
    return { valid: false, reason: 'Index name cannot start with . or _' };
  }

  // Check against blocked patterns
  for (const pattern of BLOCKED_INDEX_PATTERNS) {
    if (pattern.test(indexName)) {
      return { valid: false, reason: 'Access to this index is not permitted' };
    }
  }

  // If whitelist is configured, enforce it
  if (ALLOWED_INDICES.length > 0 && !ALLOWED_INDICES.includes(indexName)) {
    return { valid: false, reason: 'Index is not in the allowed indices list' };
  }

  return { valid: true };
}

function containsBlockedKeys(obj, blockedKeys) {
  if (obj === null || obj === undefined || typeof obj !== 'object') {
    return false;
  }

  if (Array.isArray(obj)) {
    return obj.some(item => containsBlockedKeys(item, blockedKeys));
  }

  for (const key of Object.keys(obj)) {
    if (blockedKeys.includes(key)) {
      return true;
    }
    if (containsBlockedKeys(obj[key], blockedKeys)) {
      return true;
    }
  }

  return false;
}

function sanitizeQueryBody(body) {
  if (!body || typeof body !== 'object') {
    return { valid: false, reason: 'Query body must be a valid object' };
  }

  // Check for scripting and other dangerous query types
  if (containsBlockedKeys(body, BLOCKED_QUERY_KEYS)) {
    return { valid: false, reason: 'Query contains blocked operations (e.g., scripts)' };
  }

  // Enforce size limits
  if (body.size !== undefined) {
    const size = parseInt(body.size, 10);
    if (isNaN(size) || size < 0 || size > MAX_RESULT_SIZE) {
      return { valid: false, reason: `Size must be between 0 and ${MAX_RESULT_SIZE}` };
    }
  }

  if (body.from !== undefined) {
    const from = parseInt(body.from, 10);
    if (isNaN(from) || from < 0 || from > MAX_FROM) {
      return { valid: false, reason: `From must be between 0 and ${MAX_FROM}` };
    }
  }

  return { valid: true };
}

// Simple API key authentication middleware
function authenticate(req, res, next) {
  const apiKey = req.headers['x-api-key'];
  const expectedKey = process.env.API_KEY;

  if (!expectedKey) {
    console.error('API_KEY environment variable is not set. Denying all requests.');
    return res.status(500).json({ error: 'Server misconfiguration' });
  }

  if (!apiKey || apiKey.length === 0) {
    return res.status(401).json({ error: 'Authentication required. Provide X-API-Key header.' });
  }

  // Constant-time comparison to prevent timing attacks
  if (apiKey.length !== expectedKey.length) {
    return res.status(403).json({ error: 'Invalid API key' });
  }

  const crypto = require('crypto');
  const a = Buffer.from(apiKey);
  const b = Buffer.from(expectedKey);
  if (!crypto.timingSafeEqual(a, b)) {
    return res.status(403).json({ error: 'Invalid API key' });
  }

  next();
}

app.use(authenticate);

// Search endpoint
app.post('/api/search/:index', async (req, res) => {
  try {
    const indexName = req.params.index;

    // Validate index name
    const indexValidation = validateIndexName(indexName);
    if (!indexValidation.valid) {
      return res.status(400).json({ error: indexValidation.reason });
    }

    const queryBody = req.body.query;

    // Validate query body
    if (!queryBody) {
      return res.status(400).json({ error: 'Request body must contain a "query" field' });
    }

    const queryValidation = sanitizeQueryBody(queryBody);
    if (!queryValidation.valid) {
      return res.status(400).json({ error: queryValidation.reason });
    }

    // Enforce default size if not specified
    const searchBody = { ...queryBody };
    if (searchBody.size === undefined) {
      searchBody.size = 10;
    }

    // Log the search for audit purposes
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      action: 'search',
      index: indexName,
      ip: req.ip,
      query: searchBody,
    }));

    const result = await client.search({
      index: indexName,
      body: searchBody,
    });

    return res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      took: result.took,
      timed_out: result.timed_out,
    });
  } catch (error) {
    console.error('Search error:', error.message);

    if (error.meta && error.meta.statusCode === 404) {
      return res.status(404).json({ error: 'Index not found' });
    }

    if (error.meta && error.meta.statusCode === 400) {
      return res.status(400).json({ error: 'Invalid query syntax' });
    }

    return res.status(500).json({ error: 'Internal server error' });
  }
});

// List allowed indices endpoint
app.get('/api/indices', async (req, res) => {
  try {
    const catResult = await client.cat.indices({ format: 'json' });

    const indices = catResult
      .map(idx => idx.index)
      .filter(name => {
        const validation = validateIndexName(name);
        return validation.valid;
      })
      .sort();

    return res.json({ indices });
  } catch (error) {
    console.error('List indices error:', error.message);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

